import {
    zeroAddress,
    isAddressEqual,
    isAddress,
    Address
} from "viem"

import { SOMNIA_REACTIVITY_PRECOMPILE_ADDRESS } from "@/constants"

/**
 * Validate whether a string conforms to the hex bytes32 Solidity type
 * @param value string value being tested
 * @returns True if regex passes or false if regex fails
 */
export function isValidBytes32Value(value: string): boolean {
    return /^0x[0-9a-fA-F]{64}$/.test(value);
}

/**
 * Validate whether the string argument is an ECDSA public key and that it is not the zero address
 * @param address Potentially an Ethereum address (string)
 * @returns true or false
 */
export function isValidAddress(address: string): boolean {
    if (!isAddress(address, { strict: false })) {
        return false
    }
    
    if (isAddressEqual(address, zeroAddress)) {
        return false
    }

    return true
}

export function isAddressEqualToReactivityPrecompile(address: Address): boolean {
    return isAddressEqual(address, SOMNIA_REACTIVITY_PRECOMPILE_ADDRESS)
}