import { Viem } from "@/services/viem"
import { Client } from "@/types"
import {
    WebsocketSubscriptionInitParams,
    WebSocketTransportSubscribeReturnType,
    ExtendedWebSocketTransport,
    SoliditySubscriptionData,
    SoliditySubscriptionInfo,
    BlockTickSubscription,
    ScheduleRequest,
} from "@/types/reactivity"
import {
    SomniaReactivityPrecompileABI,
    SomniaEventHandlerABI
} from "@/abi"
import {
    createPublicClient,
    webSocket,
    Hex,
    zeroAddress,
    toFunctionSelector,
    toEventSelector,
    numberToHex,
} from "viem"
import { SOMNIA_REACTIVITY_PRECOMPILE_ADDRESS, zeroBytes32 } from "@/constants"
import { isValidBytes32Value, isValidAddress, isAddressEqualToReactivityPrecompile } from "@/utils"

export class Reactivity {
    // Wrapper class on the viem web3 library providing standard ways of reading and writing to chain
    viem: Viem

    constructor(client: Client) {
        this.viem = new Viem(client)
    }

    /**
     * Typescript event subscriptions to Solidity events which bundle any ETH call result along with event log data
     * @param param0 See SubscriptionInitParams type which defines the events being observed, the eth calls executed and callback fn to call
     * @returns The node subscription identifier and an unsubscribe callback or an Error object if the subscription fails to start
     */
    public async subscribe({
        ethCalls,
        context,
        onData,
        onError,
        eventContractSources,
        topicOverrides,
        onlyPushChanges
    }: WebsocketSubscriptionInitParams): Promise<WebSocketTransportSubscribeReturnType | Error> {
        try {
            // Ensure the transport type for connected provider is websocket, otherwise we cannot proceed
            if (this.viem.client.public.transport.type !== "webSocket") {
                throw new Error("Invalid public client config - websocket required")
            }

            // get a public client with the correct websocket types already figured out
            const webSocketClient = createPublicClient({
                chain: this.viem.client.public.chain,
                transport: webSocket(),  // Defaults to chain's WS URL
            }) as unknown as { transport: ExtendedWebSocketTransport }

            // Subscribe and return the subscription info to the caller
            return webSocketClient.transport.subscribe({
                params: [
                    "somnia_watch",
                    {
                        address: eventContractSources,  // undefined means wildcard filter
                        topics: topicOverrides,         // undefined means wildcard filter
                        eth_calls: ethCalls,            // must be defined but can be empty array    
                        context,                        // undefined means no context used in eth_calls
                        push_changes_only: onlyPushChanges
                    }
                ],
                onData,
                onError
            })
        } catch (e) {
            if (e instanceof Error) {
                return e
            } else {
                return new Error(String(e))
            }
        }
    }

    /**
     * Start a subscription to events emitted by smart contracts with the callback being handled by a Solidity smart contract
     * @param subscription Defines the parameters for the subscription, mapping to wild card defaults where optional arguments are not provided
     * @returns A transaction hash if successful or a JS Error object containing failure reason
     */
    public async createSoliditySubscription(
        subscription: SoliditySubscriptionData
    ): Promise<Hex | Error> {
        // Validate the subscription and catch issues early before the precompile
        if (!isValidAddress(subscription.handlerContractAddress)) {
            return new Error("Handler contract address is invalid")
        }

        if (isAddressEqualToReactivityPrecompile(subscription.handlerContractAddress)) {
            return new Error("Handler cannot be set to the precompile")
        }

        if (subscription.maxFeePerGas === BigInt(0)) {
            return new Error("Max fee per gas cannot be zero")
        }

        if (subscription.origin && isAddressEqualToReactivityPrecompile(subscription.origin)) {
            return new Error("Origin cannot be set to the precompile")
        }

        if (subscription.caller && isAddressEqualToReactivityPrecompile(subscription.caller)) {
            return new Error("Caller cannot be set to the precompile")
        }

        if (subscription.emitter && isAddressEqualToReactivityPrecompile(subscription.emitter)) {
            return new Error("Emitter cannot be set to the precompile")
        }

        // Map SoliditySubscriptionData to an equivalent with defaults populated
        // The contract expects address(0) to declare wildcard filters
        // For event topics, specifying bytes32(0) as the first element of eventTopics means any event
        // For event topics, specifying bytes32(0) for other elements indicates unused topics
        // For event topics, array length must be 4 for the contract
        const userTopics: Hex[] = subscription.eventTopics || []
        if (!subscription.emitter && userTopics.length === 0) {
            return new Error("Emitter or event topics must be supplied at a minimum")
        }

        if (userTopics.length > 0 && !userTopics.every(isValidBytes32Value)) {
            return new Error("All eventTopics must be valid bytes32 hex strings")
        }

        const normalizedTopics = userTopics
                .slice(0, 4)
                .concat(new Array(Math.max(4 - userTopics.length, 0)).fill(zeroBytes32))
        const eventTopics: [Hex, Hex, Hex, Hex] = normalizedTopics as [Hex, Hex, Hex, Hex]
        const subscriptionWithPopulatedDefaults = {
            ...subscription,
            eventTopics,
            origin: subscription.origin ?? zeroAddress,
            caller: subscription.caller ?? zeroAddress,
            emitter: subscription.emitter ?? zeroAddress,
            handlerFunctionSelector: subscription.handlerFunctionSelector ?? toFunctionSelector(
                SomniaEventHandlerABI.filter(i => i.name === "onEvent")[0]
            )
        }

        try {
            // Broadcast the transaction to the precompile on-chain which will perform checks before creating a subscription
            const txHash = await this.viem.writeContract(
                SOMNIA_REACTIVITY_PRECOMPILE_ADDRESS,
                SomniaReactivityPrecompileABI,
                "subscribe",
                [subscriptionWithPopulatedDefaults]
            )

            if (!txHash) {
                throw new Error("Failed to broadcast TX to create on-chain subscription")
            }

            return txHash
        } catch (e) {
            if (e instanceof Error) {
                return e
            } else {
                return new Error(String(e))
            }
        }
    }

    /**
     * Cancels an active contract event subscription being handled by a solidity smart contract
     * @param subscriptionId The unique identifier for the subscription issued on subscription creation
     * @returns A transaction hash if successful or a JS Error object containing failure reason
     */
    public async cancelSoliditySubscription(
        subscriptionId: bigint
    ): Promise<Hex | Error> {
        try {
            const txHash = await this.viem.writeContract(
                SOMNIA_REACTIVITY_PRECOMPILE_ADDRESS,
                SomniaReactivityPrecompileABI,
                "unsubscribe",
                [subscriptionId]
            )

            if (!txHash) {
                throw new Error("Failed to broadcast TX to cancel on-chain subscription")
            }

            return txHash
        } catch (e) {
            if (e instanceof Error) {
                return e
            } else {
                return new Error(String(e))
            }
        }
    }

    /**
     * Create a subscription to the head of the chain reaching a specific (or any) block number
     * @param param0 The block subscription definition optionally including the block number
     * @returns Transaction hash if subscription was created or Error if a subscription was not created
     */
    public async createOnchainBlockTickSubscription({
        blockNumber,
        handlerContractAddress,
        handlerFunctionSelector,
        priorityFeePerGas,
        maxFeePerGas,
        gasLimit,
        isGuaranteed,
        isCoalesced
    }: BlockTickSubscription): Promise<Hex | Error> {
        // Compute the BlockTick event selector for the first topic filter
        const blockTickEventSelector = toEventSelector({
            name: 'BlockTick',
            type: 'event',
            inputs: [
                { type: 'uint64', indexed: true, name: 'blockNumber' }
            ]
        })

        // Compute the block number filter which may be wild card (bytes32(0)) if no number specified
        let blockNumberTopicFilter = blockNumber ? numberToHex(blockNumber, { size: 32 }) : zeroBytes32

        // Create the subscription payload for the precompile
        const subscription: SoliditySubscriptionData = {
            eventTopics: [
                blockTickEventSelector,
                blockNumberTopicFilter
            ],
            emitter: SOMNIA_REACTIVITY_PRECOMPILE_ADDRESS,
            handlerContractAddress,
            handlerFunctionSelector,
            priorityFeePerGas,
            maxFeePerGas,
            gasLimit,
            isGuaranteed,
            isCoalesced
        }

        // Fire in the request to create the block tick subscription
        return this.createSoliditySubscription(subscription)
    }

    /**
     * Schedule a smart contract callback in the future
     * @param param0 Subscription definition including the timestamp in ms
     * @returns Transaction hash if the cron was successfully scheduled or Error if a subscription was not created
     */
    public async scheduleOnchainCronJob({
        timestampMs,
        handlerContractAddress,
        handlerFunctionSelector,
        priorityFeePerGas,
        maxFeePerGas,
        gasLimit,
        isGuaranteed,
        isCoalesced
    }: ScheduleRequest): Promise<Hex | Error> {
        // Compute the Schedule event selector for the first topic filter
        const scheduleEventSelector = toEventSelector({
            name: 'Schedule',
            type: 'event',
            inputs: [
                { type: 'uint256', indexed: true, name: 'timestampMilis' }
            ]
        })

        // Ensure that the timestamp is in the future (at least 12 seconds)
        if (timestampMs < (new Date().getTime() + 12 * 1000)) {
            return new Error("Invalid timestamp - not in the future")
        }

        // Create the subscription payload for the precompile
        const subscription: SoliditySubscriptionData = {
            eventTopics: [
                scheduleEventSelector,
                numberToHex(timestampMs, { size: 32 })
            ],
            emitter: SOMNIA_REACTIVITY_PRECOMPILE_ADDRESS,
            handlerContractAddress,
            handlerFunctionSelector,
            priorityFeePerGas,
            maxFeePerGas,
            gasLimit,
            isGuaranteed,
            isCoalesced
        }

        return this.createSoliditySubscription(subscription)
    }

     /**
      * Gets the detailed parameters of a Solidity subscription given a unique subscription identifer
      * @param subscriptionId Subscription identifier
      * @returns The populated subscription or JS Error if the query failed
      */
     public async getSubscriptionInfo(
        subscriptionId: bigint
     ): Promise<SoliditySubscriptionInfo | Error> {
        try {
            return this.viem.readContract<SoliditySubscriptionInfo>(
                SOMNIA_REACTIVITY_PRECOMPILE_ADDRESS,
                SomniaReactivityPrecompileABI,
                "getSubscriptionInfo",
                [subscriptionId]
            )
        } catch (e) {
            if (e instanceof Error) {
                return e
            } else {
                return new Error(String(e))
            }
        }
     }
}